package controllers

import javax.inject._
import play.api.libs.json.Json
import play.api.mvc._
import play.api.db._
import slick.jdbc.MySQLProfile.api._

@Singleton
class ProductController @Inject() (db: Database) extends Controller {
  def search(searchParams: Map[String, String]) = Action { request =>
    val sqlFragment = """WHERE 1=1"""

    // Build WHERE clauses based on search parameters
    searchParams.foreach { case (key, value) =>
      if (value.nonEmpty) {
        sqlFragment += s""" AND $key LIKE '%$value%' """
      }
    }

    val query = sql"SELECT * FROM products $sqlFragment".as[Product]

    Ok(Json.toJson(query))
  }
